ation-history{margin-top:24px}.result h2,.generation-history h2{font-size:26px}.content{white-space:pre-wrap;color:#405c50;line-height:1.9}.tags{display:inline-block;padding:6px 10px;border-radius:12px;background:#eaf7ee;color:#287458;font-size:12px}.risk{color:#8a6d29;font-size:12px}.history-head{display:flex;align-items:end;justify-content:space-between}.history-head span{color:#6d8779;font-size:12px}.generation-list{display:grid;gap:7px;margin-top:16px}.generation-list article{display:flex;align-items:center;border:1px solid #e6eee7;border-radius:10px}.generation-open{display:grid;flex:1;gap:3px;border:0;padding:11px;background:transparent;text-align:left;cursor:pointer}.generation-open b{color:#3e574b;font-size:13px}.generation-open small{color:#849087;font-size:11px}.delete{border:0;background:transparent;padding:10px 13px;color:#ad5656;font-size:20px;cursor:pointer}.empty-history{color:#839087;font-size:13px}@media(max-width:760px){.create-page{padding:26px 16px}.head{padding:26px 22px}.head>span{display:none}.grid,.two{grid-template-columns:1fr}}
</style>
